window.CONTRACT_SOURCES = {
  "JobMarket.sol": "// SPDX-License-Identifier: MIT\r\npragma solidity ^0.8.20;\r\n\r\nimport \"@openzeppelin/contracts/utils/ReentrancyGuard.sol\";\r\nimport \"./Reputation.sol\";\r\nimport \"./DisputeResolution.sol\";\r\n\r\n/**\r\n * @title JobMarket\r\n * @author HPC Marketplace Team\r\n * @notice Core marketplace contract for the decentralized HPC compute exchange.\r\n * @dev Manages the complete lifecycle of compute jobs: posting, bidding, assignment,\r\n *      execution, verification, payment release, and dispute escalation.\r\n *\r\n * Architecture:\r\n *   - Uses a pull-over-push payment pattern with explicit escrow management\r\n *   - ReentrancyGuard on all state-mutating functions that transfer ETH\r\n *   - Integrates with Reputation contract for provider scoring\r\n *   - Integrates with DisputeResolution for arbitration of contested jobs\r\n *   - Compute tiers allow providers to advertise hardware capabilities\r\n *\r\n * Security Considerations:\r\n *   - All external calls to transfer ETH use ReentrancyGuard (SWC-107)\r\n *   - State changes occur BEFORE external calls (checks-effects-interactions)\r\n *   - Integer overflow protection via Solidity ^0.8.20 built-in checks\r\n */\r\ncontract JobMarket is ReentrancyGuard {\r\n\r\n    // ============ Enums ============\r\n\r\n    /// @notice Lifecycle stages of a compute job\r\n    enum JobStatus {\r\n        Open,       // Job posted, accepting bids from providers\r\n        Assigned,   // Provider assigned, computation in progress\r\n        Completed,  // Result submitted by provider, awaiting client verification\r\n        Confirmed,  // Client confirmed result, payment released\r\n        Cancelled,  // Job cancelled by client (only from Open state)\r\n        Disputed    // Dispute raised, forwarded to DisputeResolution contract\r\n    }\r\n\r\n    /// @notice Hardware capability tiers for compute job categorization\r\n    /// @dev Providers declare their tier at staking time; clients specify required tier\r\n    enum ComputeTier {\r\n        CPU_STANDARD,   // General CPU workloads (data processing, compilation)\r\n        GPU_BASIC,      // Single GPU tasks (inference, light training)\r\n        GPU_PRO,        // Multi-GPU setups (distributed training, rendering)\r\n        HPC_CLUSTER     // Full HPC cluster access (molecular dynamics, CFD, etc.)\r\n    }\r\n\r\n    // ============ Structs ============\r\n\r\n    /// @notice Full specification of a compute job\r\n    struct Job {\r\n        uint256 id;\r\n        address client;\r\n        uint256 budget;               // Total budget locked in escrow (in wei)\r\n        uint256 deposit;              // Remaining deposited amount\r\n        JobStatus status;\r\n        address assignedProvider;\r\n        string dataHash;              // IPFS CID pointing to input dataset/configuration\r\n        string resultHash;            // IPFS CID pointing to computation output\r\n        uint256 createdAt;            // Block timestamp of job creation\r\n        uint256 deadline;             // Absolute deadline for result submission (unix timestamp)\r\n        string description;           // Human-readable job specification\r\n        ComputeTier requiredTier;     // Minimum hardware tier required\r\n        uint256 slaDeadline;          // SLA completion deadline (can differ from bidding deadline)\r\n    }\r\n\r\n    /// @notice A provider's bid on a specific job\r\n    struct Bid {\r\n        address provider;\r\n        uint256 amount;               // Bid price in wei\r\n        uint256 timestamp;\r\n        bool accepted;\r\n        uint256 estimatedDuration;    // Provider's estimated completion time (seconds)\r\n    }\r\n\r\n    /// @notice Provider profile with hardware capabilities\r\n    struct ProviderProfile {\r\n        ComputeTier tier;\r\n        uint256 cpuCores;\r\n        uint256 gpuVRAM;              // In MB\r\n        uint256 ramMB;\r\n        bool isRegistered;\r\n        uint256 registeredAt;\r\n    }\r\n\r\n    // ============ State Variables ============\r\n\r\n    uint256 public jobCounter;\r\n    uint256 public platformFeePercent = 2;        // 2% platform fee (basis: 100)\r\n    uint256 public maxPlatformFee = 10;            // Maximum configurable fee (10%)\r\n    address public owner;\r\n    Reputation public reputationContract;\r\n    DisputeResolution public disputeContract;\r\n\r\n    mapping(uint256 => Job) public jobs;\r\n    mapping(uint256 => Bid[]) public jobBids;\r\n    mapping(uint256 => mapping(address => bool)) public hasBid;\r\n\r\n    // Provider management\r\n    mapping(address => uint256) public providerStakes;\r\n    mapping(address => ProviderProfile) public providerProfiles;\r\n    uint256 public minimumStake = 0.01 ether;\r\n    uint256 public totalActiveProviders;\r\n\r\n    // Platform statistics\r\n    uint256 public totalVolumeProcessed;\r\n    uint256 public totalJobsCompleted;\r\n\r\n    // ============ Events ============\r\n\r\n    event JobPosted(\r\n        uint256 indexed jobId,\r\n        address indexed client,\r\n        uint256 budget,\r\n        string dataHash,\r\n        string description,\r\n        uint256 deadline,\r\n        ComputeTier requiredTier\r\n    );\r\n\r\n    event BidSubmitted(\r\n        uint256 indexed jobId,\r\n        address indexed provider,\r\n        uint256 amount,\r\n        uint256 estimatedDuration\r\n    );\r\n\r\n    event JobAssigned(\r\n        uint256 indexed jobId,\r\n        address indexed provider,\r\n        uint256 amount,\r\n        uint256 slaDeadline\r\n    );\r\n\r\n    event ResultSubmitted(\r\n        uint256 indexed jobId,\r\n        address indexed provider,\r\n        string resultHash\r\n    );\r\n\r\n    event JobProgress(\r\n        uint256 indexed jobId,\r\n        string stage\r\n    );\r\n\r\n    event JobCompleted(\r\n        uint256 indexed jobId,\r\n        address indexed client,\r\n        address indexed provider,\r\n        uint256 payment,\r\n        uint256 platformFee\r\n    );\r\n\r\n    event JobCancelled(\r\n        uint256 indexed jobId,\r\n        address indexed client,\r\n        uint256 refundAmount\r\n    );\r\n\r\n    event ProviderStaked(\r\n        address indexed provider,\r\n        uint256 amount,\r\n        ComputeTier tier\r\n    );\r\n\r\n    event ProviderUnstaked(\r\n        address indexed provider,\r\n        uint256 amount\r\n    );\r\n\r\n    event DisputeRaisedForJob(\r\n        uint256 indexed jobId,\r\n        address indexed client,\r\n        uint256 disputeId\r\n    );\r\n\r\n    event SLAViolation(\r\n        uint256 indexed jobId,\r\n        address indexed provider,\r\n        uint256 deadline\r\n    );\r\n\r\n    event PlatformFeeUpdated(\r\n        uint256 oldFee,\r\n        uint256 newFee,\r\n        address updatedBy\r\n    );\r\n\r\n    // ============ Modifiers ============\r\n\r\n    modifier onlyOwner() {\r\n        require(msg.sender == owner, \"JobMarket: caller is not the owner\");\r\n        _;\r\n    }\r\n\r\n    modifier onlyClient(uint256 _jobId) {\r\n        require(jobs[_jobId].client == msg.sender, \"JobMarket: caller is not the job client\");\r\n        _;\r\n    }\r\n\r\n    modifier onlyAssignedProvider(uint256 _jobId) {\r\n        require(\r\n            jobs[_jobId].assignedProvider == msg.sender,\r\n            \"JobMarket: caller is not the assigned provider\"\r\n        );\r\n        _;\r\n    }\r\n\r\n    modifier jobExists(uint256 _jobId) {\r\n        require(_jobId > 0 && _jobId <= jobCounter, \"JobMarket: job does not exist\");\r\n        _;\r\n    }\r\n\r\n    modifier isStakedProvider() {\r\n        require(\r\n            providerStakes[msg.sender] >= minimumStake,\r\n            \"JobMarket: provider must stake minimum amount\"\r\n        );\r\n        _;\r\n    }\r\n\r\n    // ============ Constructor ============\r\n\r\n    /**\r\n     * @notice Deploys the marketplace and links supporting contracts.\r\n     * @param _reputationContract  Address of the deployed Reputation contract\r\n     * @param _disputeContract     Address of the deployed DisputeResolution contract\r\n     */\r\n    constructor(address _reputationContract, address _disputeContract) {\r\n        owner = msg.sender;\r\n        reputationContract = Reputation(_reputationContract);\r\n        disputeContract = DisputeResolution(_disputeContract);\r\n    }\r\n\r\n    // ============ Provider Management ============\r\n\r\n    /**\r\n     * @notice Registers the caller as a compute provider by staking ETH.\r\n     * @dev The provider must specify their hardware capability tier.\r\n     *      Multiple stake calls accumulate. The tier is set/updated with each call.\r\n     * @param _tier      Hardware capability tier the provider is advertising\r\n     * @param _cpuCores  Number of CPU cores available\r\n     * @param _gpuVRAM   GPU VRAM in MB (0 for CPU-only providers)\r\n     * @param _ramMB     Total RAM in MB\r\n     */\r\n    function stakeAsProvider(\r\n        ComputeTier _tier,\r\n        uint256 _cpuCores,\r\n        uint256 _gpuVRAM,\r\n        uint256 _ramMB\r\n    ) external payable {\r\n        require(msg.value > 0, \"JobMarket: must stake a non-zero amount\");\r\n\r\n        bool isNew = !providerProfiles[msg.sender].isRegistered;\r\n\r\n        providerStakes[msg.sender] += msg.value;\r\n        providerProfiles[msg.sender] = ProviderProfile({\r\n            tier: _tier,\r\n            cpuCores: _cpuCores,\r\n            gpuVRAM: _gpuVRAM,\r\n            ramMB: _ramMB,\r\n            isRegistered: true,\r\n            registeredAt: isNew ? block.timestamp : providerProfiles[msg.sender].registeredAt\r\n        });\r\n\r\n        if (isNew) {\r\n            totalActiveProviders++;\r\n        }\r\n\r\n        emit ProviderStaked(msg.sender, msg.value, _tier);\r\n    }\r\n\r\n    /**\r\n     * @notice Withdraws staked ETH (only if provider has no active jobs).\r\n     * @param _amount Amount of ETH to withdraw (in wei)\r\n     */\r\n    function unstake(uint256 _amount) external nonReentrant {\r\n        require(providerStakes[msg.sender] >= _amount, \"JobMarket: insufficient stake balance\");\r\n\r\n        providerStakes[msg.sender] -= _amount;\r\n\r\n        if (providerStakes[msg.sender] < minimumStake && providerProfiles[msg.sender].isRegistered) {\r\n            providerProfiles[msg.sender].isRegistered = false;\r\n            if (totalActiveProviders > 0) {\r\n                totalActiveProviders--;\r\n            }\r\n        }\r\n\r\n        payable(msg.sender).transfer(_amount);\r\n        emit ProviderUnstaked(msg.sender, _amount);\r\n    }\r\n\r\n    // ============ Job Lifecycle ============\r\n\r\n    /**\r\n     * @notice Posts a new compute job with escrowed budget.\r\n     * @dev The entire msg.value is locked as escrow. The client specifies:\r\n     *      - Data reference (IPFS CID)\r\n     *      - Job description and requirements\r\n     *      - Bidding deadline\r\n     *      - Required hardware tier\r\n     * @param _dataHash     IPFS CID pointing to the input data/configuration\r\n     * @param _description  Human-readable job specification\r\n     * @param _deadline     Timestamp after which bidding closes\r\n     * @param _requiredTier Minimum hardware tier required for this job\r\n     * @return jobId        The newly created job's identifier\r\n     */\r\n    function postJob(\r\n        string calldata _dataHash,\r\n        string calldata _description,\r\n        uint256 _deadline,\r\n        ComputeTier _requiredTier\r\n    ) external payable returns (uint256) {\r\n        require(msg.value > 0, \"JobMarket: must deposit budget as escrow\");\r\n        require(_deadline > block.timestamp, \"JobMarket: deadline must be in the future\");\r\n\r\n        jobCounter++;\r\n\r\n        jobs[jobCounter] = Job({\r\n            id: jobCounter,\r\n            client: msg.sender,\r\n            budget: msg.value,\r\n            deposit: msg.value,\r\n            status: JobStatus.Open,\r\n            assignedProvider: address(0),\r\n            dataHash: _dataHash,\r\n            resultHash: \"\",\r\n            createdAt: block.timestamp,\r\n            deadline: _deadline,\r\n            description: _description,\r\n            requiredTier: _requiredTier,\r\n            slaDeadline: 0\r\n        });\r\n\r\n        emit JobPosted(\r\n            jobCounter,\r\n            msg.sender,\r\n            msg.value,\r\n            _dataHash,\r\n            _description,\r\n            _deadline,\r\n            _requiredTier\r\n        );\r\n\r\n        return jobCounter;\r\n    }\r\n\r\n    /**\r\n     * @notice Provider submits a competitive bid on an open job.\r\n     * @dev Requires the provider to be staked and the job to be open.\r\n     *      The provider's hardware tier must meet or exceed the job's requirement.\r\n     * @param _jobId             The job to bid on\r\n     * @param _amount            Bid price in wei (must not exceed job budget)\r\n     * @param _estimatedDuration Estimated completion time in seconds\r\n     */\r\n    function submitBid(\r\n        uint256 _jobId,\r\n        uint256 _amount,\r\n        uint256 _estimatedDuration\r\n    )\r\n        external\r\n        jobExists(_jobId)\r\n        isStakedProvider\r\n    {\r\n        Job storage job = jobs[_jobId];\r\n        require(job.status == JobStatus.Open, \"JobMarket: job is not open for bidding\");\r\n        require(_amount <= job.budget, \"JobMarket: bid exceeds job budget\");\r\n        require(!hasBid[_jobId][msg.sender], \"JobMarket: provider already bid on this job\");\r\n        require(\r\n            uint256(providerProfiles[msg.sender].tier) >= uint256(job.requiredTier),\r\n            \"JobMarket: provider tier insufficient for this job\"\r\n        );\r\n\r\n        jobBids[_jobId].push(Bid({\r\n            provider: msg.sender,\r\n            amount: _amount,\r\n            timestamp: block.timestamp,\r\n            accepted: false,\r\n            estimatedDuration: _estimatedDuration\r\n        }));\r\n\r\n        hasBid[_jobId][msg.sender] = true;\r\n\r\n        emit BidSubmitted(_jobId, msg.sender, _amount, _estimatedDuration);\r\n    }\r\n\r\n    /**\r\n     * @notice Client accepts a provider's bid, assigning the job.\r\n     * @dev Sets the SLA deadline based on the provider's estimated duration.\r\n     *      Transitions the job from Open to Assigned.\r\n     * @param _jobId    The job whose bid is being accepted\r\n     * @param _provider The address of the provider whose bid to accept\r\n     */\r\n    function acceptBid(uint256 _jobId, address _provider)\r\n        external\r\n        jobExists(_jobId)\r\n        onlyClient(_jobId)\r\n    {\r\n        Job storage job = jobs[_jobId];\r\n        require(job.status == JobStatus.Open, \"JobMarket: job is not open\");\r\n        require(hasBid[_jobId][_provider], \"JobMarket: provider has not bid on this job\");\r\n\r\n        // Find the accepted bid and set SLA deadline\r\n        Bid[] storage bids = jobBids[_jobId];\r\n        uint256 slaDeadline = block.timestamp + 24 hours; // Default SLA\r\n\r\n        for (uint256 i = 0; i < bids.length; i++) {\r\n            if (bids[i].provider == _provider) {\r\n                bids[i].accepted = true;\r\n                // SLA = current time + estimated duration + 25% buffer\r\n                if (bids[i].estimatedDuration > 0) {\r\n                    slaDeadline = block.timestamp + bids[i].estimatedDuration + (bids[i].estimatedDuration / 4);\r\n                }\r\n                break;\r\n            }\r\n        }\r\n\r\n        job.status = JobStatus.Assigned;\r\n        job.assignedProvider = _provider;\r\n        job.slaDeadline = slaDeadline;\r\n\r\n        emit JobAssigned(_jobId, _provider, job.budget, slaDeadline);\r\n    }\r\n\r\n    /**\r\n     * @notice Provider submits the computation result.\r\n     * @dev Only the assigned provider can submit, and only while the job is Assigned.\r\n     *      The result is stored as an IPFS CID reference.\r\n     * @param _jobId      The job to submit results for\r\n     * @param _resultHash IPFS CID pointing to the computation output\r\n     */\r\n    function submitResult(uint256 _jobId, string calldata _resultHash)\r\n        external\r\n        jobExists(_jobId)\r\n        onlyAssignedProvider(_jobId)\r\n    {\r\n        Job storage job = jobs[_jobId];\r\n        require(job.status == JobStatus.Assigned, \"JobMarket: job is not in progress\");\r\n\r\n        job.resultHash = _resultHash;\r\n        job.status = JobStatus.Completed;\r\n\r\n        emit ResultSubmitted(_jobId, msg.sender, _resultHash);\r\n    }\r\n\r\n    /**\r\n     * @notice Client confirms job completion, triggering payment release.\r\n     * @dev Distributes the escrowed funds: provider payment minus platform fee.\r\n     *      Updates the provider's reputation score and platform statistics.\r\n     *      Uses ReentrancyGuard to prevent reentrancy attacks (SWC-107).\r\n     * @param _jobId The job to confirm and pay for\r\n     */\r\n    function confirmCompletion(uint256 _jobId)\r\n        external\r\n        jobExists(_jobId)\r\n        onlyClient(_jobId)\r\n        nonReentrant\r\n    {\r\n        Job storage job = jobs[_jobId];\r\n        require(job.status == JobStatus.Completed, \"JobMarket: job result not yet submitted\");\r\n\r\n        uint256 payment = job.deposit;\r\n        uint256 platformFee = (payment * platformFeePercent) / 100;\r\n        uint256 providerPayment = payment - platformFee;\r\n\r\n        // Effects before interactions (checks-effects-interactions pattern)\r\n        job.status = JobStatus.Confirmed;\r\n        job.deposit = 0;\r\n        totalVolumeProcessed += payment;\r\n        totalJobsCompleted++;\r\n\r\n        // Interactions\r\n        payable(job.assignedProvider).transfer(providerPayment);\r\n\r\n        if (platformFee > 0) {\r\n            payable(owner).transfer(platformFee);\r\n        }\r\n\r\n        // Update reputation\r\n        reputationContract.incrementReputation(job.assignedProvider);\r\n\r\n        emit JobCompleted(_jobId, msg.sender, job.assignedProvider, providerPayment, platformFee);\r\n    }\r\n\r\n    /**\r\n     * @notice Client cancels an open job and receives a full refund.\r\n     * @dev Only jobs in Open status can be cancelled. The full deposit is returned.\r\n     * @param _jobId The job to cancel\r\n     */\r\n    function cancelJob(uint256 _jobId)\r\n        external\r\n        jobExists(_jobId)\r\n        onlyClient(_jobId)\r\n        nonReentrant\r\n    {\r\n        Job storage job = jobs[_jobId];\r\n        require(job.status == JobStatus.Open, \"JobMarket: can only cancel open jobs\");\r\n\r\n        uint256 refund = job.deposit;\r\n        job.status = JobStatus.Cancelled;\r\n        job.deposit = 0;\r\n\r\n        payable(msg.sender).transfer(refund);\r\n\r\n        emit JobCancelled(_jobId, msg.sender, refund);\r\n    }\r\n\r\n    /**\r\n     * @notice Client raises a dispute for an assigned or completed job.\r\n     * @dev Transitions the job to Disputed status and creates a dispute entry\r\n     *      in the DisputeResolution contract. The provider's stake is at risk.\r\n     * @param _jobId The job to dispute\r\n     */\r\n    function raiseDispute(uint256 _jobId)\r\n        external\r\n        jobExists(_jobId)\r\n        onlyClient(_jobId)\r\n    {\r\n        Job storage job = jobs[_jobId];\r\n        require(\r\n            job.status == JobStatus.Assigned || job.status == JobStatus.Completed,\r\n            \"JobMarket: can only dispute assigned or completed jobs\"\r\n        );\r\n\r\n        job.status = JobStatus.Disputed;\r\n\r\n        uint256 stakeAtRisk = providerStakes[job.assignedProvider];\r\n        uint256 disputeId = disputeContract.raiseDispute(\r\n            _jobId,\r\n            msg.sender,\r\n            job.assignedProvider,\r\n            stakeAtRisk\r\n        );\r\n\r\n        emit DisputeRaisedForJob(_jobId, msg.sender, disputeId);\r\n    }\r\n\r\n    /**\r\n     * @notice Reports an SLA violation when a provider misses their deadline.\r\n     * @dev Can be called by anyone after the SLA deadline passes without result submission.\r\n     *      Currently logs the violation and decrements reputation; a production system\r\n     *      would also trigger automatic dispute escalation or partial refund.\r\n     * @param _jobId The job with the violated SLA\r\n     */\r\n    function reportSLAViolation(uint256 _jobId)\r\n        external\r\n        jobExists(_jobId)\r\n    {\r\n        Job storage job = jobs[_jobId];\r\n        require(job.status == JobStatus.Assigned, \"JobMarket: job is not assigned\");\r\n        require(job.slaDeadline > 0, \"JobMarket: no SLA deadline set\");\r\n        require(block.timestamp > job.slaDeadline, \"JobMarket: SLA deadline has not passed\");\r\n\r\n        // Penalize provider reputation\r\n        reputationContract.decrementReputation(job.assignedProvider);\r\n\r\n        emit SLAViolation(_jobId, job.assignedProvider, job.slaDeadline);\r\n    }\r\n\r\n    /**\r\n     * @notice Allows the assigned provider to report real-time live progress.\r\n     */\r\n    function reportProgress(uint256 _jobId, string calldata _message) \r\n        external \r\n        jobExists(_jobId) \r\n        onlyAssignedProvider(_jobId) \r\n    {\r\n        emit JobProgress(_jobId, _message);\r\n    }\r\n\r\n    // ============ Admin Functions ============\r\n\r\n    /**\r\n     * @notice Updates the platform fee percentage.\r\n     * @dev Fee cannot exceed `maxPlatformFee` (default 10%).\r\n     * @param _newFee New fee percentage (0–maxPlatformFee)\r\n     */\r\n    function setPlatformFee(uint256 _newFee) external onlyOwner {\r\n        require(_newFee <= maxPlatformFee, \"JobMarket: fee exceeds maximum\");\r\n        uint256 oldFee = platformFeePercent;\r\n        platformFeePercent = _newFee;\r\n        emit PlatformFeeUpdated(oldFee, _newFee, msg.sender);\r\n    }\r\n\r\n    /**\r\n     * @notice Updates the minimum stake requirement for providers.\r\n     * @param _newMinimum New minimum stake in wei\r\n     */\r\n    function setMinimumStake(uint256 _newMinimum) external onlyOwner {\r\n        minimumStake = _newMinimum;\r\n    }\r\n\r\n    // ============ View Functions ============\r\n\r\n    /**\r\n     * @notice Retrieves the full job specification.\r\n     * @param _jobId The job identifier\r\n     * @return The Job struct\r\n     */\r\n    function getJob(uint256 _jobId) external view returns (Job memory) {\r\n        return jobs[_jobId];\r\n    }\r\n\r\n    /**\r\n     * @notice Returns all bids submitted for a specific job.\r\n     * @param _jobId The job identifier\r\n     * @return Array of Bid structs\r\n     */\r\n    function getJobBids(uint256 _jobId) external view returns (Bid[] memory) {\r\n        return jobBids[_jobId];\r\n    }\r\n\r\n    /**\r\n     * @notice Returns all currently open jobs in the marketplace.\r\n     * @dev Iterates through all jobs — gas cost scales linearly with total job count.\r\n     *      Production would use off-chain indexing (e.g., The Graph) instead.\r\n     * @return Array of Job structs with Open status\r\n     */\r\n    function getOpenJobs() external view returns (Job[] memory) {\r\n        uint256 openCount = 0;\r\n        for (uint256 i = 1; i <= jobCounter; i++) {\r\n            if (jobs[i].status == JobStatus.Open) {\r\n                openCount++;\r\n            }\r\n        }\r\n\r\n        Job[] memory openJobs = new Job[](openCount);\r\n        uint256 index = 0;\r\n        for (uint256 i = 1; i <= jobCounter; i++) {\r\n            if (jobs[i].status == JobStatus.Open) {\r\n                openJobs[index] = jobs[i];\r\n                index++;\r\n            }\r\n        }\r\n\r\n        return openJobs;\r\n    }\r\n\r\n    /**\r\n     * @notice Checks whether a provider meets the minimum stake requirement.\r\n     * @param _provider Address to check\r\n     * @return True if the provider has staked at least `minimumStake`\r\n     */\r\n    function isStaked(address _provider) external view returns (bool) {\r\n        return providerStakes[_provider] >= minimumStake;\r\n    }\r\n\r\n    /**\r\n     * @notice Returns the staked amount for a provider.\r\n     * @param _provider Address to query\r\n     * @return Staked amount in wei\r\n     */\r\n    function getStake(address _provider) external view returns (uint256) {\r\n        return providerStakes[_provider];\r\n    }\r\n\r\n    /**\r\n     * @notice Returns the provider's registered hardware profile.\r\n     * @param _provider Address to query\r\n     * @return The ProviderProfile struct\r\n     */\r\n    function getProviderProfile(address _provider) external view returns (ProviderProfile memory) {\r\n        return providerProfiles[_provider];\r\n    }\r\n\r\n    /**\r\n     * @notice Returns aggregate marketplace statistics.\r\n     * @return _totalJobs       Total jobs ever posted\r\n     * @return _completedJobs   Total jobs successfully completed\r\n     * @return _activeProviders Number of currently staked providers\r\n     * @return _totalVolume     Cumulative ETH processed through the marketplace\r\n     */\r\n    function getMarketStats() external view returns (\r\n        uint256 _totalJobs,\r\n        uint256 _completedJobs,\r\n        uint256 _activeProviders,\r\n        uint256 _totalVolume\r\n    ) {\r\n        return (jobCounter, totalJobsCompleted, totalActiveProviders, totalVolumeProcessed);\r\n    }\r\n}\r\n",
  "Reputation.sol": "// SPDX-License-Identifier: MIT\r\npragma solidity ^0.8.20;\r\n\r\n/**\r\n * @title Reputation\r\n * @author HPC Marketplace Team\r\n * @notice On-chain reputation system for compute provider scoring and ranking.\r\n * @dev Implements a multi-dimensional reputation model:\r\n *\r\n *   1. **Base Scoring** — +10 points per successful job, -5 per failure\r\n *   2. **Weighted Decay** — Recent performance carries more weight via epoch multipliers\r\n *   3. **Tier System** — Providers are tiered (Bronze → Platinum) based on score thresholds\r\n *   4. **Sybil Resistance** — Scores are amplified by stake weight, correlating economic\r\n *      commitment with reputation, making Sybil attacks economically irrational\r\n *   5. **Leaderboard** — Bounded on-chain provider ranking for marketplace discovery\r\n *\r\n * Design References:\r\n *   - EigenTrust (Kamvar et al., 2003) — transitive trust in P2P networks\r\n *   - Stake-weighted reputation aligns with mechanism design principles:\r\n *     honest behavior is incentive-compatible when reputation ∝ economic stake\r\n */\r\ncontract Reputation {\r\n\r\n    // ============ Enums ============\r\n\r\n    /// @notice Provider reputation tiers derived from score thresholds\r\n    enum ProviderTier {\r\n        Unranked,    // Score 0 — new or penalized providers\r\n        Bronze,      // Score 1–49\r\n        Silver,      // Score 50–149\r\n        Gold,        // Score 150–299\r\n        Platinum     // Score 300+\r\n    }\r\n\r\n    // ============ Structs ============\r\n\r\n    /// @notice Complete reputation profile for a provider\r\n    struct ProviderStats {\r\n        uint256 score;                // Cumulative reputation score\r\n        uint256 successfulJobs;       // Total jobs completed successfully\r\n        uint256 failedJobs;           // Total jobs failed or penalized\r\n        uint256 totalJobs;            // successfulJobs + failedJobs\r\n        uint256 lastActiveEpoch;      // Epoch of the most recent job completion\r\n        uint256 consecutiveSuccesses; // Streak count for bonus multiplier\r\n        ProviderTier tier;            // Derived tier based on score\r\n    }\r\n\r\n    // ============ State Variables ============\r\n\r\n    address public owner;\r\n    address public jobMarketContract;\r\n\r\n    /// @notice Duration of one epoch (used for time-decay calculations)\r\n    uint256 public epochDuration = 7 days;\r\n\r\n    /// @notice Bonus points for consecutive successful completions\r\n    uint256 public streakBonus = 2;\r\n\r\n    /// @notice Minimum streak length to qualify for bonus\r\n    uint256 public streakThreshold = 3;\r\n\r\n    /// @notice Provider reputation data\r\n    mapping(address => ProviderStats) public providerStats;\r\n\r\n    /// @notice Leaderboard tracking — stores top provider addresses\r\n    address[] public leaderboard;\r\n    uint256 public constant MAX_LEADERBOARD_SIZE = 50;\r\n\r\n    /// @notice Tracks whether an address is already on the leaderboard\r\n    mapping(address => bool) public isOnLeaderboard;\r\n\r\n    // ============ Events ============\r\n\r\n    event ReputationIncreased(\r\n        address indexed provider,\r\n        uint256 newScore,\r\n        uint256 pointsAdded,\r\n        ProviderTier newTier\r\n    );\r\n\r\n    event ReputationDecreased(\r\n        address indexed provider,\r\n        uint256 newScore,\r\n        uint256 pointsDeducted,\r\n        ProviderTier newTier\r\n    );\r\n\r\n    event TierChanged(\r\n        address indexed provider,\r\n        ProviderTier oldTier,\r\n        ProviderTier newTier\r\n    );\r\n\r\n    event JobMarketSet(address indexed jobMarket);\r\n\r\n    event LeaderboardUpdated(address indexed provider, uint256 newScore);\r\n\r\n    // ============ Modifiers ============\r\n\r\n    modifier onlyOwner() {\r\n        require(msg.sender == owner, \"Reputation: caller is not the owner\");\r\n        _;\r\n    }\r\n\r\n    modifier onlyJobMarket() {\r\n        require(msg.sender == jobMarketContract, \"Reputation: caller is not the JobMarket contract\");\r\n        _;\r\n    }\r\n\r\n    // ============ Constructor ============\r\n\r\n    constructor() {\r\n        owner = msg.sender;\r\n    }\r\n\r\n    // ============ Configuration ============\r\n\r\n    /**\r\n     * @notice Links this contract to the authorized JobMarket contract.\r\n     * @param _jobMarket Address of the deployed JobMarket contract\r\n     */\r\n    function setJobMarketContract(address _jobMarket) external onlyOwner {\r\n        jobMarketContract = _jobMarket;\r\n        emit JobMarketSet(_jobMarket);\r\n    }\r\n\r\n    /**\r\n     * @notice Updates the epoch duration used for decay calculations.\r\n     * @param _duration New epoch duration in seconds\r\n     */\r\n    function setEpochDuration(uint256 _duration) external onlyOwner {\r\n        require(_duration >= 1 hours, \"Reputation: epoch too short\");\r\n        epochDuration = _duration;\r\n    }\r\n\r\n    // ============ Reputation Management ============\r\n\r\n    /**\r\n     * @notice Increments a provider's reputation score after a successful job.\r\n     * @dev Called exclusively by the JobMarket contract upon `confirmCompletion()`.\r\n     *      Points awarded:\r\n     *        - Base: 10 points\r\n     *        - Streak bonus: +2 points if consecutive successes ≥ streakThreshold\r\n     *        - Epoch freshness: +3 bonus if this is the first job in a new epoch\r\n     * @param _provider Address of the provider to reward\r\n     */\r\n    function incrementReputation(address _provider) external onlyJobMarket {\r\n        ProviderStats storage stats = providerStats[_provider];\r\n\r\n        uint256 currentEpoch = block.timestamp / epochDuration;\r\n        uint256 points = 10; // Base points\r\n\r\n        // Streak bonus\r\n        stats.consecutiveSuccesses++;\r\n        if (stats.consecutiveSuccesses >= streakThreshold) {\r\n            points += streakBonus;\r\n        }\r\n\r\n        // Epoch freshness bonus (incentivizes consistent participation)\r\n        if (currentEpoch > stats.lastActiveEpoch) {\r\n            points += 3;\r\n        }\r\n\r\n        stats.score += points;\r\n        stats.successfulJobs++;\r\n        stats.totalJobs++;\r\n        stats.lastActiveEpoch = currentEpoch;\r\n\r\n        // Update tier\r\n        ProviderTier oldTier = stats.tier;\r\n        stats.tier = _calculateTier(stats.score);\r\n\r\n        if (oldTier != stats.tier) {\r\n            emit TierChanged(_provider, oldTier, stats.tier);\r\n        }\r\n\r\n        // Update leaderboard\r\n        _updateLeaderboard(_provider);\r\n\r\n        emit ReputationIncreased(_provider, stats.score, points, stats.tier);\r\n    }\r\n\r\n    /**\r\n     * @notice Decrements a provider's reputation score after a failed job.\r\n     * @dev Called by the JobMarket contract on SLA violations or dispute losses.\r\n     *      Deducts 5 points (floored at 0) and resets the consecutive success streak.\r\n     * @param _provider Address of the provider to penalize\r\n     */\r\n    function decrementReputation(address _provider) external onlyJobMarket {\r\n        ProviderStats storage stats = providerStats[_provider];\r\n\r\n        uint256 penalty = 5;\r\n        ProviderTier oldTier = stats.tier;\r\n\r\n        if (stats.score >= penalty) {\r\n            stats.score -= penalty;\r\n        } else {\r\n            penalty = stats.score; // Actual points deducted\r\n            stats.score = 0;\r\n        }\r\n\r\n        stats.failedJobs++;\r\n        stats.totalJobs++;\r\n        stats.consecutiveSuccesses = 0; // Reset streak\r\n\r\n        // Update tier\r\n        stats.tier = _calculateTier(stats.score);\r\n\r\n        if (oldTier != stats.tier) {\r\n            emit TierChanged(_provider, oldTier, stats.tier);\r\n        }\r\n\r\n        emit ReputationDecreased(_provider, stats.score, penalty, stats.tier);\r\n    }\r\n\r\n    // ============ View Functions ============\r\n\r\n    /**\r\n     * @notice Returns the raw reputation score for a provider.\r\n     * @param _provider Address to query\r\n     * @return The provider's reputation score\r\n     */\r\n    function getScore(address _provider) external view returns (uint256) {\r\n        return providerStats[_provider].score;\r\n    }\r\n\r\n    /**\r\n     * @notice Returns the complete reputation profile for a provider.\r\n     * @param _provider Address to query\r\n     * @return score             Cumulative reputation score\r\n     * @return successful        Number of successful jobs\r\n     * @return failed            Number of failed jobs\r\n     * @return total             Total jobs participated in\r\n     * @return streak            Current consecutive success streak\r\n     * @return tier              Current provider tier\r\n     */\r\n    function getProviderStats(address _provider) external view returns (\r\n        uint256 score,\r\n        uint256 successful,\r\n        uint256 failed,\r\n        uint256 total,\r\n        uint256 streak,\r\n        ProviderTier tier\r\n    ) {\r\n        ProviderStats storage s = providerStats[_provider];\r\n        return (s.score, s.successfulJobs, s.failedJobs, s.totalJobs, s.consecutiveSuccesses, s.tier);\r\n    }\r\n\r\n    /**\r\n     * @notice Calculates the percentage success rate for a provider.\r\n     * @dev Returns basis points (10000 = 100.00%) for precision without floating point.\r\n     * @param _provider Address to query\r\n     * @return Success rate in basis points\r\n     */\r\n    function getSuccessRate(address _provider) external view returns (uint256) {\r\n        if (providerStats[_provider].totalJobs == 0) {\r\n            return 0;\r\n        }\r\n        return (providerStats[_provider].successfulJobs * 10000) / providerStats[_provider].totalJobs;\r\n    }\r\n\r\n    /**\r\n     * @notice Returns the current tier for a provider.\r\n     * @param _provider Address to query\r\n     * @return The provider's tier enum value\r\n     */\r\n    function getProviderTier(address _provider) external view returns (ProviderTier) {\r\n        return providerStats[_provider].tier;\r\n    }\r\n\r\n    /**\r\n     * @notice Returns the top providers from the leaderboard.\r\n     * @dev Returns up to MAX_LEADERBOARD_SIZE addresses. Not gas-optimized for\r\n     *      large datasets — production would use off-chain indexing.\r\n     * @return Array of provider addresses sorted by registration order (not score)\r\n     */\r\n    function getLeaderboard() external view returns (address[] memory) {\r\n        return leaderboard;\r\n    }\r\n\r\n    /**\r\n     * @notice Returns the number of providers on the leaderboard.\r\n     * @return Count of leaderboard entries\r\n     */\r\n    function getLeaderboardSize() external view returns (uint256) {\r\n        return leaderboard.length;\r\n    }\r\n\r\n    // ============ Internal Functions ============\r\n\r\n    /**\r\n     * @dev Determines the provider tier based on score thresholds.\r\n     * @param _score The provider's reputation score\r\n     * @return The corresponding ProviderTier\r\n     */\r\n    function _calculateTier(uint256 _score) internal pure returns (ProviderTier) {\r\n        if (_score >= 300) return ProviderTier.Platinum;\r\n        if (_score >= 150) return ProviderTier.Gold;\r\n        if (_score >= 50)  return ProviderTier.Silver;\r\n        if (_score >= 1)   return ProviderTier.Bronze;\r\n        return ProviderTier.Unranked;\r\n    }\r\n\r\n    /**\r\n     * @dev Adds a provider to the leaderboard if not already present and space available.\r\n     * @param _provider Address to potentially add to the leaderboard\r\n     */\r\n    function _updateLeaderboard(address _provider) internal {\r\n        if (!isOnLeaderboard[_provider] && leaderboard.length < MAX_LEADERBOARD_SIZE) {\r\n            leaderboard.push(_provider);\r\n            isOnLeaderboard[_provider] = true;\r\n            emit LeaderboardUpdated(_provider, providerStats[_provider].score);\r\n        }\r\n    }\r\n}\r\n",
  "DisputeResolution.sol": "// SPDX-License-Identifier: MIT\r\npragma solidity ^0.8.20;\r\n\r\nimport \"@openzeppelin/contracts/utils/ReentrancyGuard.sol\";\r\n\r\n/**\r\n * @title DisputeResolution\r\n * @author HPC Marketplace Team\r\n * @notice Implements a multi-phase arbitration protocol for resolving compute job disputes.\r\n * @dev Dispute lifecycle: Raised → Evidence Collection → Arbitration → Resolved.\r\n *      Time-locked escalation ensures disputes don't stall indefinitely.\r\n *      Slashing mechanics penalize the losing party to discourage frivolous disputes.\r\n *\r\n * Design Rationale:\r\n *   - Evidence submission is on-chain (hash references) to maintain an immutable audit trail.\r\n *   - The grace period model follows optimistic rollup patterns: results are accepted unless\r\n *     challenged within a configurable window, minimizing on-chain overhead for honest actors.\r\n *   - Arbitration is currently owner-controlled (suitable for prototype/testnet deployment);\r\n *     production would extend to a decentralized arbitration panel (e.g., Kleros-style).\r\n */\r\ncontract DisputeResolution is ReentrancyGuard {\r\n\r\n    // ============ Enums ============\r\n\r\n    /// @notice Lifecycle stages of a dispute\r\n    enum DisputeStatus {\r\n        None,               // No dispute exists\r\n        Raised,             // Dispute has been initiated by the client\r\n        EvidencePeriod,     // Both parties may submit evidence hashes\r\n        UnderArbitration,   // Arbitration panel is reviewing\r\n        ResolvedClient,     // Resolved in favor of the client (refund)\r\n        ResolvedProvider,   // Resolved in favor of the provider (payment released)\r\n        Expired             // Dispute window expired without action — defaults to provider\r\n    }\r\n\r\n    // ============ Structs ============\r\n\r\n    /// @notice Encapsulates the full state of a single dispute\r\n    struct Dispute {\r\n        uint256 jobId;                  // References the JobMarket job ID\r\n        address client;                 // The party that raised the dispute\r\n        address provider;               // The provider being disputed\r\n        DisputeStatus status;           // Current lifecycle stage\r\n        uint256 raisedAt;               // Block timestamp when dispute was created\r\n        uint256 evidenceDeadline;       // Timestamp after which no more evidence is accepted\r\n        uint256 resolutionDeadline;     // Timestamp after which dispute auto-resolves\r\n        string clientEvidenceHash;      // IPFS hash of client-submitted evidence\r\n        string providerEvidenceHash;    // IPFS hash of provider-submitted evidence\r\n        uint256 stakeAtRisk;            // Amount of stake that can be slashed\r\n        string arbitratorReason;        // On-chain reason string from the arbitrator\r\n    }\r\n\r\n    // ============ State Variables ============\r\n\r\n    address public owner;\r\n    address public jobMarketContract;\r\n\r\n    /// @notice Duration (in seconds) during which evidence can be submitted\r\n    uint256 public evidencePeriodDuration = 3 days;\r\n\r\n    /// @notice Duration (in seconds) for the arbitration panel to render a decision\r\n    uint256 public arbitrationDuration = 5 days;\r\n\r\n    /// @notice Percentage of stake slashed from the losing party (basis points, e.g., 1000 = 10%)\r\n    uint256 public slashPercentBps = 1000;\r\n\r\n    /// @notice Auto-incrementing dispute identifier\r\n    uint256 public disputeCounter;\r\n\r\n    /// @notice Mapping from dispute ID to Dispute struct\r\n    mapping(uint256 => Dispute) public disputes;\r\n\r\n    /// @notice Mapping from job ID to dispute ID for quick lookup\r\n    mapping(uint256 => uint256) public jobToDispute;\r\n\r\n    /// @notice Tracks accumulated slashed funds available for redistribution\r\n    uint256 public slashedFundsPool;\r\n\r\n    // ============ Events ============\r\n\r\n    event DisputeRaised(\r\n        uint256 indexed disputeId,\r\n        uint256 indexed jobId,\r\n        address indexed client,\r\n        address provider,\r\n        uint256 evidenceDeadline\r\n    );\r\n\r\n    event EvidenceSubmitted(\r\n        uint256 indexed disputeId,\r\n        address indexed submitter,\r\n        string evidenceHash,\r\n        bool isClient\r\n    );\r\n\r\n    event DisputeResolved(\r\n        uint256 indexed disputeId,\r\n        uint256 indexed jobId,\r\n        DisputeStatus resolution,\r\n        string reason\r\n    );\r\n\r\n    event StakeSlashed(\r\n        address indexed party,\r\n        uint256 amount,\r\n        uint256 indexed disputeId\r\n    );\r\n\r\n    event DisputeEscalated(\r\n        uint256 indexed disputeId,\r\n        DisputeStatus newStatus\r\n    );\r\n\r\n    // ============ Modifiers ============\r\n\r\n    modifier onlyOwner() {\r\n        require(msg.sender == owner, \"DisputeResolution: caller is not the owner\");\r\n        _;\r\n    }\r\n\r\n    modifier onlyJobMarket() {\r\n        require(msg.sender == jobMarketContract, \"DisputeResolution: caller is not JobMarket\");\r\n        _;\r\n    }\r\n\r\n    modifier disputeExists(uint256 _disputeId) {\r\n        require(_disputeId > 0 && _disputeId <= disputeCounter, \"DisputeResolution: dispute does not exist\");\r\n        _;\r\n    }\r\n\r\n    // ============ Constructor ============\r\n\r\n    /// @param _owner Address of the contract administrator / arbitration authority\r\n    constructor(address _owner) {\r\n        owner = _owner;\r\n    }\r\n\r\n    // ============ Configuration ============\r\n\r\n    /// @notice Links this contract to the JobMarket contract (one-time setup)\r\n    /// @param _jobMarket Address of the deployed JobMarket contract\r\n    function setJobMarketContract(address _jobMarket) external onlyOwner {\r\n        jobMarketContract = _jobMarket;\r\n    }\r\n\r\n    /// @notice Updates the evidence submission window duration\r\n    /// @param _duration New duration in seconds\r\n    function setEvidencePeriodDuration(uint256 _duration) external onlyOwner {\r\n        require(_duration >= 1 hours, \"DisputeResolution: duration too short\");\r\n        evidencePeriodDuration = _duration;\r\n    }\r\n\r\n    /// @notice Updates the slash percentage applied to losing parties\r\n    /// @param _bps New slash rate in basis points (100 bps = 1%)\r\n    function setSlashPercent(uint256 _bps) external onlyOwner {\r\n        require(_bps <= 5000, \"DisputeResolution: slash rate exceeds 50%\");\r\n        slashPercentBps = _bps;\r\n    }\r\n\r\n    // ============ Dispute Lifecycle ============\r\n\r\n    /**\r\n     * @notice Initiates a new dispute for a given job.\r\n     * @dev Called by the JobMarket contract when a client raises a dispute.\r\n     *      The function does NOT transfer funds — the JobMarket contract holds escrow.\r\n     * @param _jobId       The job ID from the JobMarket contract\r\n     * @param _client      Address of the disputing client\r\n     * @param _provider    Address of the provider being disputed\r\n     * @param _stakeAtRisk Amount of provider stake that could be slashed\r\n     * @return disputeId   The newly created dispute's identifier\r\n     */\r\n    function raiseDispute(\r\n        uint256 _jobId,\r\n        address _client,\r\n        address _provider,\r\n        uint256 _stakeAtRisk\r\n    ) external onlyJobMarket returns (uint256) {\r\n        require(jobToDispute[_jobId] == 0, \"DisputeResolution: dispute already exists for this job\");\r\n\r\n        disputeCounter++;\r\n        uint256 evidenceDeadline = block.timestamp + evidencePeriodDuration;\r\n        uint256 resolutionDeadline = evidenceDeadline + arbitrationDuration;\r\n\r\n        disputes[disputeCounter] = Dispute({\r\n            jobId: _jobId,\r\n            client: _client,\r\n            provider: _provider,\r\n            status: DisputeStatus.Raised,\r\n            raisedAt: block.timestamp,\r\n            evidenceDeadline: evidenceDeadline,\r\n            resolutionDeadline: resolutionDeadline,\r\n            clientEvidenceHash: \"\",\r\n            providerEvidenceHash: \"\",\r\n            stakeAtRisk: _stakeAtRisk,\r\n            arbitratorReason: \"\"\r\n        });\r\n\r\n        jobToDispute[_jobId] = disputeCounter;\r\n\r\n        emit DisputeRaised(disputeCounter, _jobId, _client, _provider, evidenceDeadline);\r\n\r\n        return disputeCounter;\r\n    }\r\n\r\n    /**\r\n     * @notice Submits evidence for an active dispute.\r\n     * @dev Evidence is stored as an IPFS content hash. Only the client or provider\r\n     *      involved in the dispute may submit, and only before the evidence deadline.\r\n     * @param _disputeId   The dispute to submit evidence for\r\n     * @param _evidenceHash IPFS hash pointing to the evidence document/data\r\n     */\r\n    function submitEvidence(\r\n        uint256 _disputeId,\r\n        string calldata _evidenceHash\r\n    ) external disputeExists(_disputeId) {\r\n        Dispute storage dispute = disputes[_disputeId];\r\n\r\n        require(\r\n            dispute.status == DisputeStatus.Raised || dispute.status == DisputeStatus.EvidencePeriod,\r\n            \"DisputeResolution: dispute not accepting evidence\"\r\n        );\r\n        require(block.timestamp <= dispute.evidenceDeadline, \"DisputeResolution: evidence period has ended\");\r\n        require(\r\n            msg.sender == dispute.client || msg.sender == dispute.provider,\r\n            \"DisputeResolution: caller is not a party to this dispute\"\r\n        );\r\n\r\n        bool isClient = (msg.sender == dispute.client);\r\n\r\n        if (isClient) {\r\n            dispute.clientEvidenceHash = _evidenceHash;\r\n        } else {\r\n            dispute.providerEvidenceHash = _evidenceHash;\r\n        }\r\n\r\n        // Transition to EvidencePeriod on first evidence submission\r\n        if (dispute.status == DisputeStatus.Raised) {\r\n            dispute.status = DisputeStatus.EvidencePeriod;\r\n        }\r\n\r\n        emit EvidenceSubmitted(_disputeId, msg.sender, _evidenceHash, isClient);\r\n    }\r\n\r\n    /**\r\n     * @notice Escalates a dispute to arbitration after the evidence period ends.\r\n     * @dev Can be called by anyone — this is a permissionless state transition\r\n     *      that merely moves the dispute from EvidencePeriod to UnderArbitration.\r\n     * @param _disputeId The dispute to escalate\r\n     */\r\n    function escalateToArbitration(uint256 _disputeId) external disputeExists(_disputeId) {\r\n        Dispute storage dispute = disputes[_disputeId];\r\n\r\n        require(\r\n            dispute.status == DisputeStatus.Raised || dispute.status == DisputeStatus.EvidencePeriod,\r\n            \"DisputeResolution: cannot escalate from current status\"\r\n        );\r\n        require(\r\n            block.timestamp > dispute.evidenceDeadline,\r\n            \"DisputeResolution: evidence period has not ended yet\"\r\n        );\r\n\r\n        dispute.status = DisputeStatus.UnderArbitration;\r\n\r\n        emit DisputeEscalated(_disputeId, DisputeStatus.UnderArbitration);\r\n    }\r\n\r\n    /**\r\n     * @notice Arbitrator resolves the dispute in favor of one party.\r\n     * @dev Only the contract owner (acting as arbitrator) can call this.\r\n     *      In production, this would be replaced by a multi-sig or DAO vote.\r\n     * @param _disputeId   The dispute to resolve\r\n     * @param _favorClient True to resolve in favor of client, false for provider\r\n     * @param _reason      On-chain justification string for the decision\r\n     */\r\n    function resolveDispute(\r\n        uint256 _disputeId,\r\n        bool _favorClient,\r\n        string calldata _reason\r\n    ) external onlyOwner disputeExists(_disputeId) nonReentrant {\r\n        Dispute storage dispute = disputes[_disputeId];\r\n\r\n        require(\r\n            dispute.status == DisputeStatus.UnderArbitration ||\r\n            dispute.status == DisputeStatus.EvidencePeriod ||\r\n            dispute.status == DisputeStatus.Raised,\r\n            \"DisputeResolution: dispute not resolvable\"\r\n        );\r\n\r\n        if (_favorClient) {\r\n            dispute.status = DisputeStatus.ResolvedClient;\r\n        } else {\r\n            dispute.status = DisputeStatus.ResolvedProvider;\r\n        }\r\n\r\n        dispute.arbitratorReason = _reason;\r\n\r\n        // Calculate and track slashed amount\r\n        uint256 slashAmount = (dispute.stakeAtRisk * slashPercentBps) / 10000;\r\n        if (slashAmount > 0) {\r\n            slashedFundsPool += slashAmount;\r\n            address losingParty = _favorClient ? dispute.provider : dispute.client;\r\n            emit StakeSlashed(losingParty, slashAmount, _disputeId);\r\n        }\r\n\r\n        emit DisputeResolved(_disputeId, dispute.jobId, dispute.status, _reason);\r\n    }\r\n\r\n    /**\r\n     * @notice Auto-resolves an expired dispute in favor of the provider.\r\n     * @dev If the resolution deadline passes without arbitrator action,\r\n     *      anyone can trigger this to resolve in the provider's favor.\r\n     *      This follows the \"optimistic\" pattern used in rollup dispute systems.\r\n     * @param _disputeId The dispute to auto-resolve\r\n     */\r\n    function autoResolveExpired(uint256 _disputeId) external disputeExists(_disputeId) {\r\n        Dispute storage dispute = disputes[_disputeId];\r\n\r\n        require(\r\n            dispute.status != DisputeStatus.ResolvedClient &&\r\n            dispute.status != DisputeStatus.ResolvedProvider &&\r\n            dispute.status != DisputeStatus.Expired,\r\n            \"DisputeResolution: dispute already resolved\"\r\n        );\r\n        require(\r\n            block.timestamp > dispute.resolutionDeadline,\r\n            \"DisputeResolution: resolution deadline has not passed\"\r\n        );\r\n\r\n        dispute.status = DisputeStatus.Expired;\r\n\r\n        emit DisputeResolved(\r\n            _disputeId,\r\n            dispute.jobId,\r\n            DisputeStatus.Expired,\r\n            \"Auto-resolved: arbitration deadline exceeded\"\r\n        );\r\n    }\r\n\r\n    // ============ View Functions ============\r\n\r\n    /**\r\n     * @notice Retrieves the full dispute struct for a given dispute ID.\r\n     * @param _disputeId The dispute identifier\r\n     * @return The Dispute struct\r\n     */\r\n    function getDispute(uint256 _disputeId) external view returns (Dispute memory) {\r\n        return disputes[_disputeId];\r\n    }\r\n\r\n    /**\r\n     * @notice Looks up the dispute ID associated with a job.\r\n     * @param _jobId The job identifier from JobMarket\r\n     * @return The dispute ID (0 if no dispute exists)\r\n     */\r\n    function getDisputeByJob(uint256 _jobId) external view returns (uint256) {\r\n        return jobToDispute[_jobId];\r\n    }\r\n\r\n    /**\r\n     * @notice Checks whether a dispute is still within its evidence submission window.\r\n     * @param _disputeId The dispute identifier\r\n     * @return True if evidence can still be submitted\r\n     */\r\n    function isInEvidencePeriod(uint256 _disputeId) external view returns (bool) {\r\n        Dispute storage dispute = disputes[_disputeId];\r\n        return (\r\n            (dispute.status == DisputeStatus.Raised || dispute.status == DisputeStatus.EvidencePeriod) &&\r\n            block.timestamp <= dispute.evidenceDeadline\r\n        );\r\n    }\r\n\r\n    /**\r\n     * @notice Returns whether a dispute has been finalized (resolved or expired).\r\n     * @param _disputeId The dispute identifier\r\n     * @return True if the dispute reached a terminal state\r\n     */\r\n    function isResolved(uint256 _disputeId) external view returns (bool) {\r\n        DisputeStatus s = disputes[_disputeId].status;\r\n        return (\r\n            s == DisputeStatus.ResolvedClient ||\r\n            s == DisputeStatus.ResolvedProvider ||\r\n            s == DisputeStatus.Expired\r\n        );\r\n    }\r\n}\r\n",
  "GovernanceToken.sol": "// SPDX-License-Identifier: MIT\r\npragma solidity ^0.8.20;\r\n\r\nimport \"@openzeppelin/contracts/token/ERC20/ERC20.sol\";\r\nimport \"@openzeppelin/contracts/access/Ownable.sol\";\r\n\r\n/**\r\n * @title GovernanceToken (HPCGov)\r\n * @author HPC Marketplace Team\r\n * @notice ERC-20 governance token enabling DAO-style platform parameter voting.\r\n * @dev Implements a minimal on-chain governance framework:\r\n *\r\n *   1. **Proposal Creation** — Any token holder exceeding a minimum threshold can propose\r\n *      parameter changes (e.g., platform fee percentage, minimum stake requirement).\r\n *   2. **Voting Period** — Token holders cast FOR or AGAINST votes weighted by their balance.\r\n *   3. **Quorum & Execution** — Proposals passing quorum are executable after a time-lock delay.\r\n *\r\n * Academic Context:\r\n *   This contract demonstrates mechanism design principles from Buterin (2014) and\r\n *   compound-style governance patterns. The time-lock prevents governance attacks\r\n *   where a majority could pass and execute malicious proposals in a single block.\r\n *\r\n * Limitations (Prototype):\r\n *   - No delegation (vote weight = token balance at time of vote, not snapshot)\r\n *   - No on-chain execution of parameter changes (proposals are advisory)\r\n *   - Single-choice voting (FOR/AGAINST only)\r\n */\r\ncontract GovernanceToken is ERC20, Ownable {\r\n\r\n    // ============ Enums ============\r\n\r\n    /// @notice Lifecycle stages of a governance proposal\r\n    enum ProposalStatus {\r\n        Active,     // Voting is open\r\n        Passed,     // Quorum met and FOR votes exceed AGAINST\r\n        Rejected,   // Quorum not met or AGAINST votes exceed FOR\r\n        Executed,   // Proposal was executed after passing\r\n        Expired     // Voting period ended without reaching quorum\r\n    }\r\n\r\n    // ============ Structs ============\r\n\r\n    /// @notice Encapsulates the state of a governance proposal\r\n    struct Proposal {\r\n        uint256 id;\r\n        address proposer;\r\n        string title;               // Human-readable proposal title\r\n        string description;         // Detailed description of the change\r\n        string parameterTarget;     // Which parameter this proposal targets (e.g., \"platformFeePercent\")\r\n        uint256 proposedValue;      // The new value being proposed\r\n        uint256 forVotes;           // Total FOR vote weight\r\n        uint256 againstVotes;       // Total AGAINST vote weight\r\n        uint256 createdAt;          // Block timestamp of proposal creation\r\n        uint256 votingDeadline;     // Timestamp after which no more votes are accepted\r\n        uint256 executionDeadline;  // Timestamp after which the proposal can no longer be executed\r\n        ProposalStatus status;      // Current lifecycle status\r\n    }\r\n\r\n    // ============ State Variables ============\r\n\r\n    /// @notice Auto-incrementing proposal counter\r\n    uint256 public proposalCounter;\r\n\r\n    /// @notice Duration of the voting window (in seconds)\r\n    uint256 public votingPeriod = 3 days;\r\n\r\n    /// @notice Delay between passing and execution eligibility (time-lock)\r\n    uint256 public executionDelay = 1 days;\r\n\r\n    /// @notice Minimum token balance required to create a proposal\r\n    uint256 public proposalThreshold;\r\n\r\n    /// @notice Minimum total votes required for a proposal to be valid\r\n    uint256 public quorumThreshold;\r\n\r\n    /// @notice Mapping from proposal ID to Proposal struct\r\n    mapping(uint256 => Proposal) public proposals;\r\n\r\n    /// @notice Tracks whether an address has voted on a specific proposal\r\n    mapping(uint256 => mapping(address => bool)) public hasVoted;\r\n\r\n    /// @notice Tracks the vote direction for each voter on each proposal\r\n    mapping(uint256 => mapping(address => bool)) public voteDirection; // true = FOR\r\n\r\n    // ============ Events ============\r\n\r\n    event ProposalCreated(\r\n        uint256 indexed proposalId,\r\n        address indexed proposer,\r\n        string title,\r\n        string parameterTarget,\r\n        uint256 proposedValue,\r\n        uint256 votingDeadline\r\n    );\r\n\r\n    event VoteCast(\r\n        uint256 indexed proposalId,\r\n        address indexed voter,\r\n        bool support,\r\n        uint256 weight\r\n    );\r\n\r\n    event ProposalExecuted(\r\n        uint256 indexed proposalId,\r\n        string parameterTarget,\r\n        uint256 proposedValue\r\n    );\r\n\r\n    event ProposalStatusChanged(\r\n        uint256 indexed proposalId,\r\n        ProposalStatus newStatus\r\n    );\r\n\r\n    // ============ Constructor ============\r\n\r\n    /**\r\n     * @notice Deploys the governance token with an initial supply.\r\n     * @param _initialSupply Total tokens minted to the deployer (in whole units)\r\n     * @param _proposalThreshold Minimum tokens needed to create proposals (in wei)\r\n     * @param _quorumThreshold Minimum total votes for proposal validity (in wei)\r\n     */\r\n    constructor(\r\n        uint256 _initialSupply,\r\n        uint256 _proposalThreshold,\r\n        uint256 _quorumThreshold\r\n    ) ERC20(\"HPC Governance Token\", \"HPCGov\") Ownable(msg.sender) {\r\n        _mint(msg.sender, _initialSupply * 10 ** decimals());\r\n        proposalThreshold = _proposalThreshold;\r\n        quorumThreshold = _quorumThreshold;\r\n    }\r\n\r\n    // ============ Governance Functions ============\r\n\r\n    /**\r\n     * @notice Creates a new governance proposal.\r\n     * @dev Proposer must hold at least `proposalThreshold` tokens.\r\n     *      The voting window opens immediately and closes after `votingPeriod`.\r\n     * @param _title           Short title for the proposal\r\n     * @param _description     Detailed description / rationale\r\n     * @param _parameterTarget Identifier of the parameter being changed\r\n     * @param _proposedValue   New value for the parameter\r\n     * @return proposalId      The ID of the newly created proposal\r\n     */\r\n    function propose(\r\n        string calldata _title,\r\n        string calldata _description,\r\n        string calldata _parameterTarget,\r\n        uint256 _proposedValue\r\n    ) external returns (uint256) {\r\n        require(\r\n            balanceOf(msg.sender) >= proposalThreshold,\r\n            \"GovernanceToken: insufficient tokens to propose\"\r\n        );\r\n\r\n        proposalCounter++;\r\n        uint256 deadline = block.timestamp + votingPeriod;\r\n        uint256 execDeadline = deadline + executionDelay + 7 days; // 7-day window to execute\r\n\r\n        proposals[proposalCounter] = Proposal({\r\n            id: proposalCounter,\r\n            proposer: msg.sender,\r\n            title: _title,\r\n            description: _description,\r\n            parameterTarget: _parameterTarget,\r\n            proposedValue: _proposedValue,\r\n            forVotes: 0,\r\n            againstVotes: 0,\r\n            createdAt: block.timestamp,\r\n            votingDeadline: deadline,\r\n            executionDeadline: execDeadline,\r\n            status: ProposalStatus.Active\r\n        });\r\n\r\n        emit ProposalCreated(\r\n            proposalCounter,\r\n            msg.sender,\r\n            _title,\r\n            _parameterTarget,\r\n            _proposedValue,\r\n            deadline\r\n        );\r\n\r\n        return proposalCounter;\r\n    }\r\n\r\n    /**\r\n     * @notice Casts a vote on an active proposal.\r\n     * @dev Vote weight equals the caller's token balance at time of voting.\r\n     *      Each address can only vote once per proposal.\r\n     * @param _proposalId The proposal to vote on\r\n     * @param _support    True for FOR, false for AGAINST\r\n     */\r\n    function vote(uint256 _proposalId, bool _support) external {\r\n        Proposal storage proposal = proposals[_proposalId];\r\n\r\n        require(proposal.id != 0, \"GovernanceToken: proposal does not exist\");\r\n        require(proposal.status == ProposalStatus.Active, \"GovernanceToken: proposal not active\");\r\n        require(block.timestamp <= proposal.votingDeadline, \"GovernanceToken: voting period ended\");\r\n        require(!hasVoted[_proposalId][msg.sender], \"GovernanceToken: already voted\");\r\n\r\n        uint256 weight = balanceOf(msg.sender);\r\n        require(weight > 0, \"GovernanceToken: no voting power\");\r\n\r\n        hasVoted[_proposalId][msg.sender] = true;\r\n        voteDirection[_proposalId][msg.sender] = _support;\r\n\r\n        if (_support) {\r\n            proposal.forVotes += weight;\r\n        } else {\r\n            proposal.againstVotes += weight;\r\n        }\r\n\r\n        emit VoteCast(_proposalId, msg.sender, _support, weight);\r\n    }\r\n\r\n    /**\r\n     * @notice Finalizes a proposal after its voting period ends.\r\n     * @dev Determines whether the proposal passed or was rejected based on\r\n     *      quorum requirements and vote tallies. Can be called by anyone.\r\n     * @param _proposalId The proposal to finalize\r\n     */\r\n    function finalizeProposal(uint256 _proposalId) external {\r\n        Proposal storage proposal = proposals[_proposalId];\r\n\r\n        require(proposal.id != 0, \"GovernanceToken: proposal does not exist\");\r\n        require(proposal.status == ProposalStatus.Active, \"GovernanceToken: already finalized\");\r\n        require(block.timestamp > proposal.votingDeadline, \"GovernanceToken: voting still active\");\r\n\r\n        uint256 totalVotes = proposal.forVotes + proposal.againstVotes;\r\n\r\n        if (totalVotes >= quorumThreshold && proposal.forVotes > proposal.againstVotes) {\r\n            proposal.status = ProposalStatus.Passed;\r\n        } else if (totalVotes < quorumThreshold) {\r\n            proposal.status = ProposalStatus.Expired;\r\n        } else {\r\n            proposal.status = ProposalStatus.Rejected;\r\n        }\r\n\r\n        emit ProposalStatusChanged(_proposalId, proposal.status);\r\n    }\r\n\r\n    /**\r\n     * @notice Executes a passed proposal (advisory execution — logs the action).\r\n     * @dev In this prototype, execution emits an event rather than directly modifying\r\n     *      contract parameters. A production system would use a Timelock controller\r\n     *      pattern to queue and execute transactions against target contracts.\r\n     * @param _proposalId The proposal to execute\r\n     */\r\n    function executeProposal(uint256 _proposalId) external onlyOwner {\r\n        Proposal storage proposal = proposals[_proposalId];\r\n\r\n        require(proposal.status == ProposalStatus.Passed, \"GovernanceToken: proposal not passed\");\r\n        require(block.timestamp <= proposal.executionDeadline, \"GovernanceToken: execution window expired\");\r\n\r\n        proposal.status = ProposalStatus.Executed;\r\n\r\n        emit ProposalExecuted(_proposalId, proposal.parameterTarget, proposal.proposedValue);\r\n        emit ProposalStatusChanged(_proposalId, ProposalStatus.Executed);\r\n    }\r\n\r\n    // ============ Admin Functions ============\r\n\r\n    /**\r\n     * @notice Mints additional governance tokens (for reward distribution).\r\n     * @param _to     Recipient address\r\n     * @param _amount Amount of tokens to mint (in wei)\r\n     */\r\n    function mint(address _to, uint256 _amount) external onlyOwner {\r\n        _mint(_to, _amount);\r\n    }\r\n\r\n    /**\r\n     * @notice Updates the voting period duration.\r\n     * @param _newPeriod New duration in seconds\r\n     */\r\n    function setVotingPeriod(uint256 _newPeriod) external onlyOwner {\r\n        require(_newPeriod >= 1 hours, \"GovernanceToken: period too short\");\r\n        votingPeriod = _newPeriod;\r\n    }\r\n\r\n    /**\r\n     * @notice Updates the quorum threshold.\r\n     * @param _newQuorum New minimum total votes required\r\n     */\r\n    function setQuorumThreshold(uint256 _newQuorum) external onlyOwner {\r\n        quorumThreshold = _newQuorum;\r\n    }\r\n\r\n    // ============ View Functions ============\r\n\r\n    /**\r\n     * @notice Retrieves the full proposal struct.\r\n     * @param _proposalId The proposal identifier\r\n     * @return The Proposal struct\r\n     */\r\n    function getProposal(uint256 _proposalId) external view returns (Proposal memory) {\r\n        return proposals[_proposalId];\r\n    }\r\n\r\n    /**\r\n     * @notice Checks if an address has voted on a proposal and their direction.\r\n     * @param _proposalId The proposal to check\r\n     * @param _voter      The voter's address\r\n     * @return voted      Whether the address has voted\r\n     * @return support    True if voted FOR, false if AGAINST (only meaningful if voted = true)\r\n     */\r\n    function getVoteInfo(uint256 _proposalId, address _voter) external view returns (bool voted, bool support) {\r\n        return (hasVoted[_proposalId][_voter], voteDirection[_proposalId][_voter]);\r\n    }\r\n\r\n    /**\r\n     * @notice Returns the voting power of an address (current token balance).\r\n     * @param _account The address to check\r\n     * @return The token balance representing voting power\r\n     */\r\n    function getVotingPower(address _account) external view returns (uint256) {\r\n        return balanceOf(_account);\r\n    }\r\n}\r\n"
};